// Configure the ADS1115 read parameters from subflow env vars.
const channelId = Number(env.get('channel_id'));
const address = env.get('i2c_address');
const channelName = env.get('channel_name');
const dividerRatio = Number(env.get('divider_ratio')) || 1.0;

if (isNaN(channelId) || channelId < 0 || channelId > 3) {
    node.error(`Invalid channel_id: ${env.get('channel_id')} (must be 0-3)`, msg);
    return null;
}

// Stash config for the format node downstream.
msg._adc_config = { channelName, dividerRatio, channelId, address };

// Configure the ads1x15 node's read parameters via msg.
msg.address = parseInt(address, 16) || 0x48;
msg.mux = channelId;  // single-ended: 0=A0-GND, 1=A1-GND, 2=A2-GND, 3=A3-GND

return msg;

// Reshape the raw ADS1115 reading into the standard node output.
const config = msg._adc_config || {};
const rawValue = msg.payload;  // ads1x15 puts the raw 16-bit signed value here

// Convert raw to voltage. ADS1115 with gain=1 has ±4.096V range over ±32767 counts.
// Then multiply by divider ratio to get the actual pre-divider voltage.
const voltsPerCount = 4.096 / 32767;
const voltageAtPin = rawValue * voltsPerCount;
const actualVoltage = voltageAtPin * config.dividerRatio;

msg.payload = {
    name: config.channelName,
    channel: config.channelId,
    raw: rawValue,
    voltage: Number(actualVoltage.toFixed(4)),
    timestamp: new Date().toISOString()
};

// Clean up internal fields.
delete msg._adc_config;
delete msg.address;
delete msg.mux;

return msg;
